-- SEARCH_TEXT カラムに検索対象のテキストが入ります。

CREATE OR REPLACE TABLE IDOM_HANDSON.DATA_MART.ACTIVITY_SEARCH_CHUNKS (
    ACTIVITY_ID VARCHAR(20),
    NEGOTIATION_ID VARCHAR(20),
    STORE_ID VARCHAR(10),
