    ASSIGNED_USER_NAME VARCHAR(100),
    ACTIVITY_TYPE VARCHAR(50),
    ACTIVITY_DATE TIMESTAMP_NTZ(9),
    SUBJECT VARCHAR(200),
    SEARCH_TEXT VARCHAR(16777216)
);

